import React, { useState, useEffect } from "react";
import axios from "axios";
import ReactLoading from "react-loading";
import Swal from 'sweetalert2';
let Money_Button = require("@moneybutton/react-money-button").default;

// import Paypal from "./Paypal";
const MoneyButton = ({payloadObj}) => {
  const [buttonLoaded, setButtonLoaded] = useState(false);
  const [payload, setPayload] = useState({});

  useEffect(() => {
    let uPayload = payloadObj;
    if (uPayload) {
      setPayload(uPayload);
    }
  }, []);

  const onMoneyButtonPayment = (payment) => {
    setButtonLoaded(true);
    let data = {
        tenantId: payload.tenantId,
        organizationId: payload.organizationId,
        invoiceId: payload.invoiceId,
        vendorId: payload.vendorId,
        version: payload.version,
        paidAmount: payload.amount,
        updatedBy: payload.email,
        paymentID: "",
        payerID: "",
        paymentType: payload.paymentType,
        currencyType: payload.currencyType,
        orderId: "",
        paymentGateway: payload.paymentBy,
        currencyCode: payload.currencyCode,
        balanceDue: payload.balanceDue,
        paymentMethod: payload.paymentMethod,
        transactionFee: payload.transactionFee,
    };
    axios({
      method: "post",
      url: `${process.env.REACT_APP_LDOCS_API_URL}/payment/invoicePayment`,
      data: data,
      headers: {
        cooljwt: payload.Token,
      },
    })
      .then(async (response) => {
        Swal.fire({
          title: "Success",
          text: "Payment Successful.",
          icon: "success",
          showCancelButton: false,
          confirmButtonColor: "#49b34e",
          cancelButtonColor: "#d33",
          confirmButtonText: "Success",
        });
      })
      .catch((err) => {
        Swal.fire({
          title: "Error",
          text: "Payment Unsuccessful.",
          icon: "error",
          showCancelButton: false,
          confirmButtonColor: "#49b34e",
          cancelButtonColor: "#d33",
          confirmButtonText: "OK",
        });
      });}

  return (
    <React.Fragment>
      {buttonLoaded == false ?
      <div
      style={{ position: "absolute", top: "40%" }}
      >
       <ReactLoading type={"spokes"} color="#290818" /> 
      </div>
      : ""}
    <div
      style={{
        padding: 0,
          margin: 0,
          listStyle: "none",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          position: "absolute",
          top: "40%",
      }}
    >
      <Money_Button
        style={{
          marginTop: "20px",
          display: buttonLoaded ? "block" : "none",
        }}
        to={payload.moneyButtonEmail}
        amount={
          payload.amount
        }
        label="Pay Now"
        onError={() => {
          Swal.fire({
            title: "Success",
            text: "Issue in Load Money Button .",
            icon: "success",
            showCancelButton: false,
            confirmButtonColor: "#49b34e",
            cancelButtonColor: "#d33",
            confirmButtonText: "Success",
          });
        }}
        onLoad={(payload) => setButtonLoaded(true)}
        onPayment={onMoneyButtonPayment}
        successMessage="Payment SuccessFully Transfered"
        devMode={payloadObj.dev ? payloadObj.dev : true }
        currency={payload.currencyCode}
      />
      
    </div>
    </React.Fragment>
  );
};

export default MoneyButton;
