import React, { useState, useEffect } from "react";
import Paypal from "./components/Paypal";
import MoneyButton from "./components/MoneyButton";

// import Paypal from "./Paypal";
const App = () => {
  const [method, setMethod] = useState(null);
  const [payload, setPayload] = useState({
    tenantId: "",
    organizationId: "",
    invoiceId: "",
    vendorId: "",
    version: "",
    amount: "12",
    email: "",
    paypalEmail: "sb-bymml6171154@business.example.com",
    paymentType: "",
    currencyType: "",
    paymentBy: "",
    currencyCode: "USD",
    balanceDue: "20",
    paymentMethod: "",
    transactionFee: "0",
    merchantId: "",
    clientId: "",
    Token: "",
    moneyButtonEmail: "47759@moneybutton.com",
    dev:true
  });

  //Get Url Params
  const getParameterByName = (name, url) => {
    if (!url) url = window.location.href;
    name = name.replace(/[\[\]]/g, "\\$&");
    var regex = new RegExp("[?&]" + name + "(=([^&#]*)|&|#|$)");
    var results = regex.exec(url);
    if (!results) return null;
    if (!results[2]) return "";
    return decodeURIComponent(results[2].replace(/\+/g, " "));
  };

  useEffect(() => {
    let paymentMethod = getParameterByName("method");
    setMethod(paymentMethod);
    let urlPayload = getParameterByName("payload");
    let uPayload = JSON.parse(urlPayload);
    if (uPayload) {
       setPayload(uPayload);
    }
  }, []);

  return (
    <React.Fragment>
      <div style={{
       padding:20,
       background:"#f44336",
       color:'white',
       left:0,
       right:0,
       position:'absolute',
       top:0
     }}>
  <strong>Note! </strong> Please do not close Popup until payment is done.

     </div>
    <div
      style={{
        padding: 0,
        margin: 0,
        listStyle: "none",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      {/* if Paypal */}
      {method == 1 ? <Paypal payloadObj={payload} /> : ""}
      {/* if MonetButton */}
      {method == 2 ? <MoneyButton payloadObj={payload} /> : ""}

      {method == null ? "Please select a Payment Method .." : ""}
    </div>
    </React.Fragment>

  );
};

export default App;
